svg.script:

(function () {
  'use strict';

  var SVG_NS = 'http://www.w3.org/2000/svg';

  // Measure actual monospace character dimensions from the browser's rendered font
  var measureEl = document.getElementById('measure');
  var measureBBox = measureEl.getBBox();
  var CELL_W = measureBBox.width / 10;
  if (!CELL_W || CELL_W <= 0) CELL_W = 8.4;
  var CELL_H = measureBBox.height;
  if (!CELL_H || CELL_H <= 0) CELL_H = 17;

  // -----------------------------------------------------------------------
  // Parse URL params from the SVG's own URL
  // -----------------------------------------------------------------------
  var docUrl = document.URL || '';
  var urlParams = (function () {
    var map = {};
    var qIdx = docUrl.indexOf('?');
    if (qIdx === -1) return map;
    var query = docUrl.slice(qIdx + 1);
    query.split('&').forEach(function (part) {
      var eqIdx = part.indexOf('=');
      if (eqIdx === -1) return;
      var key = decodeURIComponent(part.slice(0, eqIdx));
      var val = decodeURIComponent(part.slice(eqIdx + 1));
      map[key] = val;
    });
    return map;
  })();

  var SESSION = urlParams['session'] || '';
  var PANE    = urlParams['pane']    || '0';
  var SERVER  = (urlParams['server'] || '').replace(/\/$/, '');

  // -----------------------------------------------------------------------
  // Element references
  // -----------------------------------------------------------------------
  var root         = document.getElementById('root');
  var textLayer    = document.getElementById('text-layer');
  var bgLayer      = document.getElementById('bg-layer');
  var linkLayer    = document.getElementById('link-layer');
  var cursorEl     = document.getElementById('cursor');
  var errorOverlay = document.getElementById('error-overlay');


  // -----------------------------------------------------------------------
  // State
  // -----------------------------------------------------------------------
  var columns     = 0;
  var rows        = 0;
  var prevState   = [];   // array of JSON strings, one per row
  var initialized = false;
  var pollTimer    = null;
  var pollInterval = 150;
  var RETRY_MS     = 2000;

  var ws              = null;
  var useWebSocket    = false;
  var allLines        = [];
  var wsReconnectTimer = null;

  // -----------------------------------------------------------------------
  // Helpers
  // -----------------------------------------------------------------------
  function apiUrl(path) {
    return SERVER + path;
  }

  function showError() {
    errorOverlay.setAttribute('visibility', 'visible');
  }

  function hideError() {
    errorOverlay.setAttribute('visibility', 'hidden');
  }

  function schedulePoll(ms) {
    if (pollTimer !== null) {
      clearTimeout(pollTimer);
    }
    pollTimer = setTimeout(poll, ms);
  }

  function stopPolling() {
    if (pollTimer !== null) {
      clearTimeout(pollTimer);
      pollTimer = null;
    }
  }

  // -----------------------------------------------------------------------
  // Line rendering — each tspan gets an explicit x position
  // -----------------------------------------------------------------------
  function updateLine(index, spans) {
    var text = document.getElementById('r' + index);
    if (!text) return;
    while (text.firstChild) {
      text.removeChild(text.firstChild);
    }
    var charOffset = 0;
    for (var i = 0; i < spans.length; i++) {
      var span = spans[i];
      var tspan = document.createElementNS(SVG_NS, 'tspan');
      tspan.textContent = span.text;
      // Position each tspan at its character offset
      tspan.setAttribute('x', (charOffset * CELL_W).toFixed(2));
      var classes = [];
      if (span.cls)  classes.push(span.cls);
      if (span.bold) classes.push('bold');
      if (span.italic) classes.push('italic');
      if (span.dim)  classes.push('dim');
      if (classes.length) tspan.setAttribute('class', classes.join(' '));
      if (span.fg)   tspan.setAttribute('fill', span.fg);
      if (span.underline)     tspan.setAttribute('text-decoration', 'underline');
      if (span.strikethrough) tspan.setAttribute('text-decoration', 'line-through');
      text.appendChild(tspan);
      charOffset += span.text.length;
    }
  }

  function rebuildBgLayer(lines) {
    while (bgLayer.firstChild) {
      bgLayer.removeChild(bgLayer.firstChild);
    }
    for (var row = 0; row < lines.length; row++) {
      var spans = lines[row].spans;
      var colOffset = 0;
      for (var s = 0; s < spans.length; s++) {
        var span = spans[s];
        var hasBg = (span.bg != null) || (span.bgCls != null);
        if (hasBg) {
          var rect = document.createElementNS(SVG_NS, 'rect');
          rect.setAttribute('x', (colOffset * CELL_W).toFixed(2));
          rect.setAttribute('y', row * CELL_H);
          rect.setAttribute('width', (span.text.length * CELL_W).toFixed(2));
          rect.setAttribute('height', CELL_H);
          if (span.bgCls) {
            rect.setAttribute('class', span.bgCls);
          } else if (span.bg) {
            rect.setAttribute('fill', span.bg);
          }
          bgLayer.appendChild(rect);
        }
        colOffset += span.text.length;
      }
    }
  }

  // Render blue underlines for URLs in terminal text.
  // Checks span.url (set by server-side sgr-parser) AND scans text for
  // http:// / https:// patterns (for claude-proxy sessions where
  // screen-renderer.ts doesn't tag URLs). Click handling by dashboard layer.
  // Find URLs in span text — returns array of {start, end, url}
  function findUrlsInText(text) {
    var urls = [];
    var searchFrom = 0;
    while (searchFrom < text.length) {
      var httpIdx = text.indexOf('http://', searchFrom);
      var httpsIdx = text.indexOf('https://', searchFrom);
      var idx = -1;
      if (httpIdx >= 0 && httpsIdx >= 0) idx = Math.min(httpIdx, httpsIdx);
      else if (httpIdx >= 0) idx = httpIdx;
      else if (httpsIdx >= 0) idx = httpsIdx;
      if (idx < 0) break;
      var end = idx;
      while (end < text.length && !/[\s<>"'\])]/.test(text[end])) end++;
      while (end > idx && /[.,;:!?)}\]]/.test(text[end - 1])) end--;
      if (end - idx > 7) {
        urls.push({ start: idx, end: end, url: text.slice(idx, end) });
      }
      searchFrom = end;
    }
    return urls;
  }

  function rebuildLinkLayer(lines) {
    while (linkLayer.firstChild) linkLayer.removeChild(linkLayer.firstChild);

    // Build full text per line for multi-line URL detection
    var lineTexts = [];
    for (var li = 0; li < lines.length; li++) {
      var lt = '';
      var sp = lines[li].spans;
      for (var si = 0; si < sp.length; si++) lt += sp[si].text;
      lineTexts.push(lt);
    }

    // Detect multi-line URLs: if a URL starts on one line and the line ends at
    // the terminal width (no trailing whitespace), continue concatenating the next
    // line(s) until we hit whitespace or an empty/short line.
    var multiLineUrls = [];
    // Get terminal width from viewBox (reliable) — not from text length
    var vb = document.getElementById('root').getAttribute('viewBox');
    var termCols = 80;
    if (vb) {
      var vbParts = vb.split(/\s+/);
      if (CELL_W > 0) termCols = Math.round(parseFloat(vbParts[2]) / CELL_W);
    }
    for (var row = 0; row < lineTexts.length; row++) {
      var text = lineTexts[row];
      if (text.indexOf('http') >= 0) {
        console.log('[URL-scan] row=' + row + ' len=' + text.length + ' text="' + text.substring(0, 80) + '"');
      }
      var httpIdx = text.indexOf('https://');
      if (httpIdx < 0) httpIdx = text.indexOf('http://');
      if (httpIdx < 0) continue;
      // Build URL by concatenating this line from httpIdx to end, then
      // subsequent lines that look like URL continuation (no leading space,
      // non-empty, and the URL text has no whitespace break)
      var urlText = text.slice(httpIdx).trimEnd();
      var endRow = row;
      while (endRow < lineTexts.length - 1) {
        var nextText = lineTexts[endRow + 1];
        if (!nextText || nextText.length === 0) break;
        // If current URL text ends with a URL-safe char and next line starts
        // with a URL-safe char (no space), it's a continuation
        var lastChar = urlText[urlText.length - 1];
        var firstChar = nextText[0];
        if (/\s/.test(firstChar)) break; // next line starts with space — not continuation
        if (/\s/.test(lastChar)) break;  // current ends with space — URL ended
        endRow++;
        urlText += nextText.trimEnd();
      }
      // Find actual URL end in concatenated text
      var urlEnd = 0;
      while (urlEnd < urlText.length && !/[\s<>"']/.test(urlText[urlEnd])) urlEnd++;
      while (urlEnd > 0 && /[.,;:!?)}\]]/.test(urlText[urlEnd - 1])) urlEnd--;
      if (urlEnd <= 7) continue;
      var fullUrl = urlText.slice(0, urlEnd);
      console.log('[URL] rows ' + row + '-' + endRow + ' len=' + fullUrl.length + ' url=' + fullUrl.substring(0, 60) + '...');
      // Build segments per line
      var segments = [];
      var remaining = urlEnd;
      var segStartCol = httpIdx;
      for (var sr = row; sr <= endRow && remaining > 0; sr++) {
        var lineLen = lineTexts[sr].length;
        var segEnd = Math.min(segStartCol + remaining, lineLen);
        segments.push({ row: sr, startCol: segStartCol, endCol: segEnd });
        remaining -= (segEnd - segStartCol);
        segStartCol = 0; // subsequent lines start at col 0
      }
      multiLineUrls.push({ url: fullUrl, startRow: row, segments: segments });
      row = endRow; // skip processed lines
    }

    // Draw underlines for multi-line URLs
    for (var mi = 0; mi < multiLineUrls.length; mi++) {
      var mlu = multiLineUrls[mi];
      for (var si = 0; si < mlu.segments.length; si++) {
        var seg = mlu.segments[si];
        var ul = document.createElementNS(SVG_NS, 'line');
        ul.setAttribute('x1', (seg.startCol * CELL_W).toFixed(2));
        ul.setAttribute('y1', ((seg.row + 1) * CELL_H - 1).toFixed(2));
        ul.setAttribute('x2', (seg.endCol * CELL_W).toFixed(2));
        ul.setAttribute('y2', ((seg.row + 1) * CELL_H - 1).toFixed(2));
        ul.setAttribute('stroke', '#5c8fff');
        ul.setAttribute('stroke-width', '1');
        ul.setAttribute('opacity', '0.6');
        ul.setAttribute('data-url', mlu.url);
        ul.appendChild(document.createElementNS(SVG_NS, 'title')); // tooltip
        ul.lastChild.textContent = mlu.url;
        linkLayer.appendChild(ul);
      }
    }

    // Also do per-line detection for single-line URLs not caught above
    var multiLineRows = new Set();
    for (var mi = 0; mi < multiLineUrls.length; mi++) {
      for (var si = 0; si < multiLineUrls[mi].segments.length; si++) {
        multiLineRows.add(multiLineUrls[mi].segments[si].row);
      }
    }

    for (var row = 0; row < lines.length; row++) {
      if (multiLineRows.has(row)) continue; // already handled by multi-line detection
      var spans = lines[row].spans;
      var colOffset = 0;
      for (var s = 0; s < spans.length; s++) {
        var span = spans[s];
        if (span.url) {
          var underline = document.createElementNS(SVG_NS, 'line');
          underline.setAttribute('x1', (colOffset * CELL_W).toFixed(2));
          underline.setAttribute('y1', ((row + 1) * CELL_H - 1).toFixed(2));
          underline.setAttribute('x2', ((colOffset + span.text.length) * CELL_W).toFixed(2));
          underline.setAttribute('y2', ((row + 1) * CELL_H - 1).toFixed(2));
          underline.setAttribute('stroke', '#5c8fff');
          underline.setAttribute('stroke-width', '1');
          underline.setAttribute('opacity', '0.6');
          underline.setAttribute('data-url', span.url);
          linkLayer.appendChild(underline);
        } else {
          var found = findUrlsInText(span.text);
          for (var u = 0; u < found.length; u++) {
            var ul = document.createElementNS(SVG_NS, 'line');
            ul.setAttribute('x1', ((colOffset + found[u].start) * CELL_W).toFixed(2));
            ul.setAttribute('y1', ((row + 1) * CELL_H - 1).toFixed(2));
            ul.setAttribute('x2', ((colOffset + found[u].end) * CELL_W).toFixed(2));
            ul.setAttribute('y2', ((row + 1) * CELL_H - 1).toFixed(2));
            ul.setAttribute('stroke', '#5c8fff');
            ul.setAttribute('stroke-width', '1');
            ul.setAttribute('opacity', '0.6');
            ul.setAttribute('data-url', found[u].url);
            linkLayer.appendChild(ul);
          }
        }
        colOffset += span.text.length;
      }
    }
  }

  // -----------------------------------------------------------------------
  // Initialization: set up row <text> elements
  // -----------------------------------------------------------------------
  function initLayout(width, height) {
    columns = width;
    rows = height;

    // Clear any existing text rows
    while (textLayer.firstChild) {
      textLayer.removeChild(textLayer.firstChild);
    }

    // Set viewBox based on measured cell width
    root.setAttribute('viewBox', '0 0 ' +
      (width * CELL_W).toFixed(2) + ' ' + (height * CELL_H));

    // Update cursor size to match measured cell width
    cursorEl.setAttribute('width', CELL_W.toFixed(2));
    cursorEl.setAttribute('height', CELL_H.toFixed(2));

    // Create one <text> element per row — no textLength, tspans handle positioning
    for (var row = 0; row < height; row++) {
      var text = document.createElementNS(SVG_NS, 'text');
      text.setAttribute('id', 'r' + row);
      text.setAttribute('y', row * CELL_H);
      textLayer.appendChild(text);
    }

    // Initialize prevState
    prevState = new Array(height).fill(null);
    initialized = true;
  }

  // -----------------------------------------------------------------------
  // WebSocket — REMOVED (Task 8, session authz hardening)
  // Per-card /ws/terminal removed. Dashboard's shared WS pushes screen
  // data via renderMessage(); input routed via cpRequest('input').
  // ws variable and useWebSocket kept for sendToWs() fallback detection.
  // -----------------------------------------------------------------------

  // -----------------------------------------------------------------------
  // DEPRECATED (PRD v0.5.0): HTTP polling fallback
  // Replaced by shared WebSocket via dashboard.mjs + renderMessage().
  // Kept for old pre-WebSocket tmux sessions during transition.
  // The safety-net schedulePoll on startup causes 404/500 errors on new sessions.
  // -----------------------------------------------------------------------
  function poll() {
    pollTimer = null;
    if (useWebSocket) return;

    var url = apiUrl('/api/pane?pane=' + encodeURIComponent(PANE));
    if (SESSION) {
      url += '&session=' + encodeURIComponent(SESSION);
    }

    fetch(url)
      .then(function (res) {
        if (!res.ok) {
          throw new Error('HTTP ' + res.status);
        }
        return res.json();
      })
      .then(function (data) {
        var width  = data.width;
        var height = data.height;
        var lines  = data.lines;
        var cursor = data.cursor;

        // First-time init or dimension change
        if (!initialized ||
            columns !== width || rows !== height) {
          initLayout(width, height);
        }

        // Diff and update changed lines
        var anyChanged = false;
        for (var i = 0; i < lines.length; i++) {
          var serialized = JSON.stringify(lines[i].spans);
          if (serialized !== prevState[i]) {
            updateLine(i, lines[i].spans);
            prevState[i] = serialized;
            anyChanged = true;
          }
        }
        allLines = lines;  // keep allLines in sync for rebuildBgLayer after WS reconnect

        // Rebuild background layer if anything changed
        if (anyChanged) {
          rebuildBgLayer(lines); rebuildLinkLayer(lines);
        }

        // Update cursor position
        if (cursor) {
          cursorEl.setAttribute('x', (cursor.x * CELL_W).toFixed(2));
          cursorEl.setAttribute('y', cursor.y * CELL_H);
        }

        hideError();
        schedulePoll(pollInterval);
      })
      .catch(function (err) {
        if (!useWebSocket) showError();
        schedulePoll(RETRY_MS);
      });
  }

  // -----------------------------------------------------------------------
  // Tier measurement — returns target poll interval based on rendered size
  // -----------------------------------------------------------------------
  function measureTier() {
    var el = document.getElementById('r0');
    if (!el) return 150;
    var rect = el.getBoundingClientRect();
    if (!rect || rect.width === 0) return 150;
    var charWidth  = columns > 0 ? rect.width / columns : 0;
    var charHeight = rect.height;
    if (charWidth >= 4 && charHeight >= 6) return 150;
    return 2000;
  }

  // -----------------------------------------------------------------------
  // startPolling — set interval and kick off polling if not already running
  // -----------------------------------------------------------------------
  function startPolling(ms) {
    pollInterval = ms;
    if (pollTimer === null) {
      poll();
    }
  }

  // -----------------------------------------------------------------------
  // IntersectionObserver — stop polling when offscreen, resume when visible
  // -----------------------------------------------------------------------
  // DISABLED: IntersectionObserver polling removed — shared WS handles data (PRD v0.5.0)
  // if (typeof IntersectionObserver !== 'undefined') {
  //   var observer = new IntersectionObserver(function (entries) {
  //     var entry = entries[0];
  //     if (!entry.isIntersecting) { stopPolling(); }
  //     else { startPolling(measureTier()); }
  //   });
  //   observer.observe(document.documentElement);
  // }

  // -----------------------------------------------------------------------
  // Resize listener — debounced, rechecks tier and updates pollInterval
  // -----------------------------------------------------------------------
  var resizeTimer = null;
  window.addEventListener('resize', function () {
    if (resizeTimer !== null) clearTimeout(resizeTimer);
    resizeTimer = setTimeout(function () {
      resizeTimer = null;
      var newTier = measureTier();
      if (newTier !== pollInterval) {
        pollInterval = newTier;
      }
    }, 200);
  });

  // -----------------------------------------------------------------------
  // Text Selection — mouse drag selects terminal text, copies to clipboard
  // -----------------------------------------------------------------------
  var selLayer = document.getElementById('sel-layer');
  var selStart = null;   // { row, col }
  var selEnd = null;     // { row, col }
  var isSelecting = false;

  function pixelToCell(e) {
    // Convert mouse event coordinates to terminal row/col
    var pt = root.createSVGPoint();
    pt.x = e.clientX;
    pt.y = e.clientY;
    var svgPt = pt.matrixTransform(root.getScreenCTM().inverse());
    var col = Math.floor(svgPt.x / CELL_W);
    var row = Math.floor(svgPt.y / CELL_H);
    col = Math.max(0, Math.min(col, columns - 1));
    row = Math.max(0, Math.min(row, rows - 1));
    return { row: row, col: col };
  }

  function drawSelection() {
    // Clear previous selection highlights
    while (selLayer.firstChild) {
      selLayer.removeChild(selLayer.firstChild);
    }
    if (!selStart || !selEnd) return;

    // Normalize: startPos is earlier, endPos is later
    var startPos, endPos;
    if (selStart.row < selEnd.row || (selStart.row === selEnd.row && selStart.col <= selEnd.col)) {
      startPos = selStart;
      endPos = selEnd;
    } else {
      startPos = selEnd;
      endPos = selStart;
    }

    for (var row = startPos.row; row <= endPos.row; row++) {
      var c1 = (row === startPos.row) ? startPos.col : 0;
      var c2 = (row === endPos.row) ? endPos.col : columns - 1;
      var rect = document.createElementNS(SVG_NS, 'rect');
      rect.setAttribute('x', (c1 * CELL_W).toFixed(2));
      rect.setAttribute('y', (row * CELL_H).toFixed(2));
      rect.setAttribute('width', ((c2 - c1 + 1) * CELL_W).toFixed(2));
      rect.setAttribute('height', CELL_H.toFixed(2));
      rect.setAttribute('class', 'sel-highlight');
      selLayer.appendChild(rect);
    }
  }

  function getSelectedText() {
    if (!selStart || !selEnd || !allLines.length) return '';

    var startPos, endPos;
    if (selStart.row < selEnd.row || (selStart.row === selEnd.row && selStart.col <= selEnd.col)) {
      startPos = selStart;
      endPos = selEnd;
    } else {
      startPos = selEnd;
      endPos = selStart;
    }

    var lines = [];
    for (var row = startPos.row; row <= endPos.row; row++) {
      if (!allLines[row]) continue;
      // Build the full text for this row from spans
      var fullLine = '';
      var spans = allLines[row].spans;
      for (var s = 0; s < spans.length; s++) {
        fullLine += spans[s].text;
      }
      var c1 = (row === startPos.row) ? startPos.col : 0;
      var c2 = (row === endPos.row) ? endPos.col + 1 : fullLine.length;
      lines.push(fullLine.substring(c1, c2));
    }
    // Trim trailing whitespace from each line, then join
    return lines.map(function(l) { return l.replace(/\s+$/, ''); }).join('\n');
  }

  function clearSelection() {
    selStart = null;
    selEnd = null;
    isSelecting = false;
    while (selLayer.firstChild) {
      selLayer.removeChild(selLayer.firstChild);
    }
  }

  root.addEventListener('mousedown', function(e) {
    if (e.button !== 0) return;
    // Don't start selection if ctrl is held (ctrl+click is for multi-focus in dashboard)
    if (e.ctrlKey) return;
    selStart = pixelToCell(e);
    selEnd = selStart;
    isSelecting = true;
    drawSelection();
  });

  root.addEventListener('mousemove', function(e) {
    if (!isSelecting) return;
    selEnd = pixelToCell(e);
    drawSelection();
  });

  root.addEventListener('mouseup', function(e) {
    if (!isSelecting) return;
    isSelecting = false;
    selEnd = pixelToCell(e);
    drawSelection();

    // Copy to clipboard if there's a real selection (not just a click)
    if (selStart && selEnd && (selStart.row !== selEnd.row || selStart.col !== selEnd.col)) {
      var text = getSelectedText();
      if (text && navigator.clipboard && navigator.clipboard.writeText) {
        navigator.clipboard.writeText(text).catch(function() {});
      }
    }
  });

  // Clear selection when new content arrives (screen is changing)
  // This prevents stale highlights from lingering
  var selClearOnUpdate = false;

  // --- Parent integration (single-WebSocket architecture) ---
  // Dashboard routes input/scroll through this WebSocket via contentWindow.sendToWs()
  // instead of opening a second WebSocket connection. Returns true if sent, false if WS unavailable.
  window.sendToWs = function(msg) {
    if (ws && ws.readyState === 1) {
      ws.send(JSON.stringify(msg));
      return true;
    }
    return false;
  };

  // -----------------------------------------------------------------------
  // Inbound API — dashboard pushes data via shared WebSocket (PRD v0.5.0)
  // Same rendering as ws.onmessage but called externally by dashboard.mjs.
  // Old ws.onmessage path kept for old sessions during transition.
  // -----------------------------------------------------------------------
  var _sharedWsActive = false;
  function nudgeObjectRepaint() {
    try {
      var fe = window.frameElement;
      if (!fe) return;
      var rootEl = document.documentElement;
      requestAnimationFrame(function() {
        requestAnimationFrame(function() {
          fe.style.opacity = '0.9999';
          rootEl.setAttribute('data-ts', String(Date.now()));
          void fe.offsetHeight;
          fe.style.opacity = '';
          rootEl.removeAttribute('data-ts');
        });
      });
    } catch (e) {}
  }
  window.renderMessage = function(msg) {
    _sharedWsActive = true;
    if (msg.type === 'screen') {
      if (!initialized || columns !== msg.width || rows !== msg.height) {
        initLayout(msg.width, msg.height);
      }
      allLines = msg.lines;
      for (var i = 0; i < msg.lines.length; i++) {
        updateLine(i, msg.lines[i].spans);
        prevState[i] = JSON.stringify(msg.lines[i].spans);
      }
      rebuildBgLayer(msg.lines); rebuildLinkLayer(msg.lines);
      if (msg.cursor) {
        cursorEl.setAttribute('x', (msg.cursor.x * CELL_W).toFixed(2));
        cursorEl.setAttribute('y', msg.cursor.y * CELL_H);
      }
      hideError();
      try { if (window._screenCallback) window._screenCallback(msg); } catch(e) {}
      nudgeObjectRepaint();

    } else if (msg.type === 'delta') {
      var keys = Object.keys(msg.changed);
      for (var k = 0; k < keys.length; k++) {
        var idx = parseInt(keys[k]);
        var lineData = msg.changed[keys[k]];
        var spans = lineData.spans || lineData;
        updateLine(idx, spans);
        allLines[idx] = { spans: spans };
        prevState[idx] = JSON.stringify(spans);
      }
      if (keys.length > 0) { rebuildBgLayer(allLines); rebuildLinkLayer(allLines); }
      if (msg.cursor) {
        cursorEl.setAttribute('x', (msg.cursor.x * CELL_W).toFixed(2));
        cursorEl.setAttribute('y', msg.cursor.y * CELL_H);
      }
      try { if (window._screenCallback) window._screenCallback(msg); } catch(e) {}
      hideError();
      nudgeObjectRepaint();

    } else if (msg.type === 'error') {
      showError();
    }
  };

  // -----------------------------------------------------------------------
  // Start
  // -----------------------------------------------------------------------
  if (SESSION) {
    // Per-card /ws/terminal removed (Task 8). Dashboard shared WS
    // delivers screen data via renderMessage(). Nothing to start here.
  } else if (!SESSION) {
    // Standalone viewer removed — no polling needed
  }
})();
